/* ═══════════════════════════════════════════════════════════
   MESA DE APROVAÇÃO — ANINHA / DIOGO
   Recebe comandos do Telegram e processa aprovações.
   Comandos aceitos:
     APROVAR <ID>   → Aprova e libera workflow
     REVISAR <ID>   → Marca para revisão
     REJEITAR <ID>  → Bloqueia execução
     STATUS         → Lista pendências
   ═══════════════════════════════════════════════════════════ */

const msg = $input.item.json;
const text = (msg.message?.text || msg.callback_query?.data || '').trim().toUpperCase();
const chatId = msg.message?.chat?.id || msg.callback_query?.message?.chat?.id || '';
const userName = msg.message?.from?.first_name || msg.callback_query?.from?.first_name || 'Operador';

let resposta = '';
let acao = 'desconhecido';
let targetId = '';

if (text.startsWith('APROVAR')) {
  targetId = text.replace('APROVAR', '').trim();
  acao = 'aprovar';
  resposta = `✅ *APROVADO* por ${userName}\nWorkflow/Item: ${targetId || 'geral'}\nData: ${new Date().toLocaleString('pt-BR')}`;
} else if (text.startsWith('REVISAR')) {
  targetId = text.replace('REVISAR', '').trim();
  acao = 'revisar';
  resposta = `🔄 *MARCADO PARA REVISÃO* por ${userName}\nWorkflow/Item: ${targetId || 'geral'}\nData: ${new Date().toLocaleString('pt-BR')}`;
} else if (text.startsWith('REJEITAR')) {
  targetId = text.replace('REJEITAR', '').trim();
  acao = 'rejeitar';
  resposta = `❌ *REJEITADO* por ${userName}\nWorkflow/Item: ${targetId || 'geral'}\nData: ${new Date().toLocaleString('pt-BR')}`;
} else if (text === 'STATUS') {
  acao = 'status';
  resposta = `📊 *STATUS DA MESA DE APROVAÇÃO*\nOperador: ${userName}\nConsulta: ${new Date().toLocaleString('pt-BR')}\n\n_Nenhuma pendência no momento._`;
} else {
  resposta = `⚠️ Comando não reconhecido: "${text}"\n\nComandos válidos:\n• APROVAR <ID>\n• REVISAR <ID>\n• REJEITAR <ID>\n• STATUS`;
}

return [{
  json: {
    acao,
    target: targetId,
    operador: userName,
    chat_id: chatId,
    resposta,
    timestamp: new Date().toISOString()
  }
}];
